#[test]
fn test_theme_switch_performance() {
    let context = Arc::new(ThemeContext::new(Theme::from_preset(Preset::Dark)));

    let styles: Vec<_> = (0..100)
        .map(|_| Style::themed(&context).foreground_slot(ColorSlot::Primary))
